<?php namespace App\Repositories\Events;use App\Repositories\BaseRepository;use App\Models\Events\Club;use Illuminate\Database\Eloquent\Collection;class ClubRepository extends BaseRepository{    public function __construct(Club $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Club    {        return $this->query()->where('name', $name)->first();    }    public function findByCode(string $code): ?Club    {        return $this->query()->where('code', $code)->first();    }    public function getActiveClubs(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function getByAdvisor(int $employeeId): Collection    {        return $this->findByField('advisor_id', $employeeId);    }    public function searchClubs(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getClubWithMembers(int $clubId): ?Club    {        return $this->query()->with('members')->findOrFail($clubId);    }    public function countMembersByClub(): Collection    {        return $this->query()->withCount('members')->get();    }}